              "id": "mqtssbla9gp8d",
              "title": "Explore Color Spaces (HSV, Lab) and Segmentation Basics",
              "description": "Convert images between different color spaces (BGR, RGB, HSV, Lab) using `cv2.cvtColor()`. Understand the advantages of HSV for color-based segmentation and Lab for perceptual uniformity. Implement a basic color-based segmentation algorithm using `cv2.inRange()` to isolate objects of a specific color.",
              "labels": [],
              "color": null,
              "links": [],
              "images": [],
              "createdAt": 1782409820590,
